import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.doppler.com/reference/api";
const PLACEHOLDER_VALUE = "dp.st.CoffeeSafeLocalCoffeeSafeLocalCoffeeSafe00";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Doppler API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:doppler",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const dopplerFirewall = {",
    '  name: "doppler",',
    '  description: "Doppler",',
    "  placeholders: {",
    `    DOPPLER_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.doppler.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.DOPPLER_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Doppler firewall config...");
  const ts = generateTypeScript();
  writeOutput("doppler", ts, import.meta.dirname);
}
